import{_ as a,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Monitoreo de calidad de energía","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-quality/monitoring.md","filePath":"es/power-quality/monitoring.md"}'),s={name:"es/power-quality/monitoring.md"};function n(l,e,t,c,d,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="monitoreo-de-calidad-de-energia" tabindex="-1">Monitoreo de calidad de energía <a class="header-anchor" href="#monitoreo-de-calidad-de-energia" aria-label="Permalink to &quot;Monitoreo de calidad de energía&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>El monitoreo de calidad de energía es el proceso de medir y analizar parámetros eléctricos para detectar perturbaciones y evaluar el desempeño del sistema.</p><p>Proporciona visibilidad sobre cómo se comportan el voltaje, la corriente y las condiciones de la forma de onda a lo largo del tiempo.</p><p>El monitoreo es esencial para identificar problemas como caídas de voltaje, sobretensiones, armónicos y transitorios.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito del monitoreo de calidad de energía es:</p><ul><li>Detectar y registrar perturbaciones de calidad de energía</li><li>Identificar la fuente de problemas eléctricos</li><li>Apoyar la resolución de problemas y las acciones correctivas</li><li>Verificar el desempeño del sistema y el cumplimiento normativo</li><li>Mejorar la confiabilidad y reducir el tiempo de inactividad</li></ul><p>Sin monitoreo, muchos problemas de calidad de energía permanecen inadvertidos hasta que ocurren fallas.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Los sistemas de monitoreo utilizan dispositivos de medición instalados en puntos clave del sistema eléctrico.</p><p>Estos dispositivos registran continuamente parámetros tales como:</p><ul><li>Niveles de voltaje y corriente</li><li>Frecuencia</li><li>Distorsión armónica</li><li>Perturbaciones basadas en eventos como caídas de voltaje o sobretensiones</li></ul><p>Los datos se almacenan y analizan para identificar patrones, tendencias y eventos anormales.</p><p>Los sistemas avanzados pueden activar alarmas o generar informes cuando se superan los umbrales.</p><p>El monitoreo puede ser:</p><ul><li>Continuo para sistemas críticos</li><li>Temporal para resolver problemas específicos</li></ul><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>El monitoreo de calidad de energía se utiliza en:</p><ul><li>Instalaciones industriales con equipos sensibles</li><li>Sistemas que experimentan perturbaciones frecuentes</li><li>Infraestructura crítica que requiere alta confiabilidad</li><li>Instalaciones con altos niveles de cargas no lineales</li><li>Programas de gestión y optimización de energía</li></ul><p>Es valioso tanto durante la validación del diseño como en la operación continua.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Ubicación de la medición</strong><br> Los puntos de monitoreo deben seleccionarse para capturar datos relevantes</p></li><li><p><strong>Parámetros monitoreados</strong><br> Deben alinearse con los problemas esperados, como armónicos o eventos de voltaje</p></li><li><p><strong>Resolución de datos</strong><br> Los eventos de alta velocidad requieren tasas de muestreo adecuadas</p></li><li><p><strong>Análisis de datos</strong><br> Se necesitan herramientas y experiencia para interpretar los resultados</p></li><li><p><strong>Integración</strong><br> Los sistemas de monitoreo pueden conectarse a SCADA o plataformas de datos</p></li><li><p><strong>Costo y complejidad</strong><br> Deben equilibrarse con la importancia del sistema</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Instalar monitores en cargas principales y críticas proporciona mejor visibilidad</li><li>El monitoreo temporal es útil para diagnosticar problemas intermitentes</li><li>Los datos a largo plazo ayudan a identificar patrones recurrentes y causas raíz</li><li>Una interpretación deficiente de los datos puede llevar a conclusiones incorrectas</li><li>El monitoreo debe combinarse con acciones correctivas para lograr una mejora real</li></ul>',25)])])}const b=a(s,[["render",n]]);export{u as __pageData,b as default};
